@strawberry.type
class Query:
    @strawberry.field
    def product(self, info: Info, id: int) -> Optional[ProductType]:
        session = info.context.get("session")
        return session.query(Product).filter(Product.id == id).first()
    
    @strawberry.field
    def products(self, info: Info) -> List[ProductType]:
        session = info.context.get("session")
        return session.query(Product).all()
    
    @strawberry.field
    def category(self, info: Info, id: int) -> Optional[CategoryType]:
        session = info.context.get("session")
        return session.query(Category).filter(Category.id == id).first()
    
    @strawberry.field
    def categories(self, info: Info) -> List[CategoryType]:
        session = info.context.get("session")
        return session.query(Category).all()

